class Cat:
    def __init__(self, name):
        self.name = name

    def meow(self):
        print(self.name + " says Meow!")

kitty = Cat("Whiskers")
kitty.meow()

class Player:
    def __init__(self, name):
        self.name = name
        self.score = 20

    def add_points(self, points):
        self.score = self.score + points

    def lose_points(self, points):
        self.score = self.score - points

p = Player("Sam")
p.add_points(10)
p.lose_points(5)
print("Score:", p.score)
